class Calculator:
    def __init__(self, num1, num2):
        self.num1 = num1
        self.num2 = num2

    def add(self):
        return self.num1 + self.num2

    def subtract(self):
        return self.num1 - self.num2

    def multiply(self):
        return self.num1 * self.num2

    def divide(self):
        return self.num1 / self.num2

a, b = map(int, input().split())
calc = Calculator(a, b)

print(calc.add())
print(calc.subtract())
print(calc.multiply())
print(calc.divide())
